// Lookup helpers -----------------------------------------------------------
export const CATEGORY_BY_ID: Record<string, CategoryNode> = (() => {
  const map: Record<string, CategoryNode> = {};
  for (const c of CATEGORIES_FULL) {
    map[c.id] = c;
    for (const s of c.children ?? []) map[s.id] = s;
  }
  return map;
})();

export const CATEGORY_BY_SLUG: Record<string, CategoryNode> = (() => {
  const map: Record<string, CategoryNode> = {};
  for (const c of CATEGORIES_FULL) {
    map[c.slug] = c;
    for (const s of c.children ?? []) map[`${c.slug}/${s.slug}`] = s;
  }
  return map;
})();

export function findCategory(name: string): CategoryNode | undefined {
  return CATEGORIES_FULL.find((c) => c.name === name);
}

export function findSubcategory(catName: string, subName: string): CategoryNode | undefined {
  return findCategory(catName)?.children?.find((s) => s.name === subName);
}
